302: 	// Compare entries removing keybindings
303: 	if (!equals(value1.filter(({ command }) => command[0] === '-'), value2.filter(({ command }) => command[0] === '-'), (a, b) => isSameKeybinding(a, b))) {
304: 		return false;
305: 	}
